import fs from 'fs';
import { execSync } from 'child_process';

// Run eslint to get JSON output
try {
  execSync('npx eslint . --format json > lint-results.json', { stdio: 'pipe' });
} catch (e) {
  // eslint exits with 1 if there are errors, but we still get the json
}

const results = JSON.parse(fs.readFileSync('lint-results.json', 'utf8'));

results.forEach(fileResult => {
  if (fileResult.messages.length === 0) return;

  const filePath = fileResult.filePath;
  let lines = fs.readFileSync(filePath, 'utf8').split('\n');

  // Apply changes from bottom to top so line numbers don't shift
  const messages = fileResult.messages.sort((a, b) => {
    if (b.line === a.line) return b.column - a.column;
    return b.line - a.line;
  });

  messages.forEach(msg => {
    if (msg.ruleId === 'no-unused-vars') {
      const lineIdx = msg.line - 1;
      let lineText = lines[lineIdx];

      // Specifically target "motion"
      if (msg.message.includes("'motion'")) {
        lineText = lineText.replace(/,\s*motion\b/g, '');
        lineText = lineText.replace(/\bmotion\s*,\s*/g, '');
        lineText = lineText.replace(/import\s*{\s*motion\s*}\s*from\s*['"]framer-motion['"];?/g, '');
        lineText = lineText.replace(/import\s*{\s*}\s*from\s*['"]framer-motion['"];?/g, '');
        if (lineText.trim() === "import  from 'framer-motion';" || lineText.trim() === 'import { } from "framer-motion";' || lineText.trim() === "import { } from 'framer-motion'") {
           lineText = "";
        }
      }
      // Target other specific ones like 'err'
      else if (msg.message.includes("'err'")) {
         lineText = lineText.replace('err', '_err');
      }
      else if (msg.message.includes("'useAuth'")) {
         lineText = lineText.replace(/,\s*useAuth\b/g, '');
      }
      else if (msg.message.includes("'prev'")) {
         lineText = lineText.replace('prev', '_prev');
      }
      else if (msg.message.includes("'editingGoal'")) {
         lineText = lineText.replace('editingGoal', '_editingGoal');
      }
      else if (msg.message.includes("'setIsGoogleConnected'")) {
         lineText = lineText.replace('setIsGoogleConnected', '_setIsGoogleConnected');
      }
      else if (msg.message.includes("'limit'")) {
         lineText = lineText.replace(/,\s*limit\b/g, '');
      }
      else if (msg.message.includes("'getFirestore'")) {
         lineText = lineText.replace(/,\s*getFirestore\b/g, '');
      }
      else if (msg.message.includes("'getFunctions'")) {
         lineText = lineText.replace(/,\s*getFunctions\b/g, '');
      }
      else if (msg.message.includes("'result'")) {
         lineText = lineText.replace('result', '_result');
      }
      else if (msg.message.includes("'addTodo'")) {
         lineText = lineText.replace(/,\s*addTodo\b/g, '');
      }
      else if (msg.message.includes("'currentUser'")) {
         lineText = lineText.replace(/,\s*currentUser\b/g, '');
         lineText = lineText.replace(/\bcurrentUser\s*,\s*/g, '');
      }

      lines[lineIdx] = lineText;
    }
  });

  fs.writeFileSync(filePath, lines.join('\n'));
});

import { useState, useRef, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { FaRobot, FaUser, FaPaperPlane, FaSpinner, FaComments, FaTimes } from 'react-icons/fa'
import OpenRouterService from '../services/OpenRouterService'
import { useAuth } from '../context/AuthContext'

const AIChatAssistant = () => {
  const { currentUser } = useAuth()
  const [isOpen, setIsOpen] = useState(false)
  const [messages, setMessages] = useState([
    {
      id: 1,
      type: 'ai',
      content: "Hi! I'm your AI productivity coach. I can help you with task prioritization, goal setting, habit building, and productivity strategies. What would you like to work on today?",
      timestamp: new Date()
    }
  ])
  const [inputMessage, setInputMessage] = useState('')
  const [isTyping, setIsTyping] = useState(false)
  const messagesEndRef = useRef(null)

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }

  useEffect(() => {
    scrollToBottom()
  }, [messages])

  const sendMessage = async () => {
    if (!inputMessage.trim() || isTyping) return

    const userMessage = {
      id: Date.now(),
      type: 'user',
      content: inputMessage,
      timestamp: new Date()
    }

    setMessages(prev => [...prev, userMessage])
    setInputMessage('')
    setIsTyping(true)

    try {
      // Create context-aware prompt
      const systemPrompt = `You are an AI productivity coach integrated into FlowNest, a productivity management platform. 
      You help users with:
      - Task prioritization and time management
      - Goal setting and achievement strategies
      - Habit formation and tracking
      - Productivity techniques (Pomodoro, time blocking, etc.)
      - Work-life balance and stress management
      - Motivation and accountability

      Keep responses concise, actionable, and encouraging. Ask follow-up questions to better understand the user's needs.
      User context: ${currentUser?.displayName || 'User'} is using FlowNest for productivity management.`

      const conversationHistory = messages.slice(-5).map(msg => ({
        role: msg.type === 'user' ? 'user' : 'assistant',
        content: msg.content
      }))

      const response = await OpenRouterService.makeRequest([
        { role: 'system', content: systemPrompt },
        ...conversationHistory,
        { role: 'user', content: inputMessage }
      ], { temperature: 0.7, maxTokens: 300 })

      const aiMessage = {
        id: Date.now() + 1,
        type: 'ai',
        content: response.choices[0].message.content,
        timestamp: new Date()
      }

      setMessages(prev => [...prev, aiMessage])
    } catch (error) {
      console.error('Chat error:', error)
      const errorMessage = {
        id: Date.now() + 1,
        type: 'ai',
        content: "I'm sorry, I'm having trouble connecting right now. Please try again in a moment.",
        timestamp: new Date()
      }
      setMessages(prev => [...prev, errorMessage])
    } finally {
      setIsTyping(false)
    }
  }

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      sendMessage()
    }
  }

  const formatTime = (date) => {
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
  }

  return (
    <>
      {/* Chat Toggle Button */}
      <motion.button
        onClick={() => setIsOpen(!isOpen)}
        className="fixed bottom-6 right-6 w-14 h-14 bg-gradient-to-r from-purple-500 to-blue-500 text-white rounded-full shadow-lg hover:shadow-xl transition-all duration-300 flex items-center justify-center z-50"
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
      >
        {isOpen ? <FaTimes size={20} /> : <FaComments size={20} />}
      </motion.button>

      {/* Chat Window */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.95 }}
            className="fixed bottom-24 right-6 w-80 h-96 bg-white dark:bg-gray-800 rounded-xl shadow-2xl border border-gray-200 dark:border-gray-700 flex flex-col z-40"
          >
            {/* Header */}
            <div className="p-4 border-b border-gray-200 dark:border-gray-700 bg-gradient-to-r from-purple-500 to-blue-500 text-white rounded-t-xl">
              <div className="flex items-center">
                <FaRobot className="mr-2" />
                <div>
                  <h3 className="font-semibold">AI Productivity Coach</h3>
                  <p className="text-xs opacity-90">Always here to help</p>
                </div>
              </div>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-3">
              {messages.map((message) => (
                <div
                  key={message.id}
                  className={`flex ${message.type === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  <div className={`flex items-start space-x-2 max-w-[80%] ${message.type === 'user' ? 'flex-row-reverse space-x-reverse' : ''}`}>
                    <div className={`w-6 h-6 rounded-full flex items-center justify-center text-xs ${
                      message.type === 'user' 
                        ? 'bg-blue-500 text-white' 
                        : 'bg-purple-500 text-white'
                    }`}>
                      {message.type === 'user' ? <FaUser /> : <FaRobot />}
                    </div>
                    <div className={`rounded-lg p-3 ${
                      message.type === 'user'
                        ? 'bg-blue-500 text-white'
                        : 'bg-gray-100 dark:bg-gray-700 text-gray-900 dark:text-white'
                    }`}>
                      <p className="text-sm whitespace-pre-wrap">{message.content}</p>
                      <p className={`text-xs mt-1 opacity-70 ${
                        message.type === 'user' ? 'text-blue-100' : 'text-gray-500 dark:text-gray-400'
                      }`}>
                        {formatTime(message.timestamp)}
                      </p>
                    </div>
                  </div>
                </div>
              ))}

              {isTyping && (
                <div className="flex justify-start">
                  <div className="flex items-start space-x-2">
                    <div className="w-6 h-6 rounded-full bg-purple-500 text-white flex items-center justify-center text-xs">
                      <FaRobot />
                    </div>
                    <div className="bg-gray-100 dark:bg-gray-700 rounded-lg p-3">
                      <div className="flex space-x-1">
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                      </div>
                    </div>
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div className="p-4 border-t border-gray-200 dark:border-gray-700">
              <div className="flex space-x-2">
                <textarea
                  value={inputMessage}
                  onChange={(e) => setInputMessage(e.target.value)}
                  onKeyPress={handleKeyPress}
                  placeholder="Ask me about productivity, goals, habits..."
                  className="flex-1 resize-none input-field text-sm h-10 py-2"
                  rows="1"
                  disabled={isTyping}
                />
                <button
                  onClick={sendMessage}
                  disabled={!inputMessage.trim() || isTyping}
                  className="btn-primary px-3 py-2 disabled:opacity-50"
                >
                  {isTyping ? <FaSpinner className="animate-spin" /> : <FaPaperPlane />}
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  )
}

export default AIChatAssistant

import { useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { FaBullseye, FaRobot, FaPlus, FaCheck, FaClock, FaSpinner } from 'react-icons/fa'
import OpenRouterService from '../services/OpenRouterService'
import { useAuth } from '../context/AuthContext'
import { addDoc, collection } from 'firebase/firestore'
import { db } from '../utils/firebase'

const AIGoalBreakdown = () => {
  const { currentUser } = useAuth()
  const [goalInput, setGoalInput] = useState('')
  const [isAnalyzing, setIsAnalyzing] = useState(false)
  const [breakdown, setBreakdown] = useState(null)
  const [showBreakdown, setShowBreakdown] = useState(false)

  const analyzeGoal = async () => {
    if (!goalInput.trim()) return

    setIsAnalyzing(true)
    try {
      const result = await OpenRouterService.breakdownGoal(goalInput)
      setBreakdown(result)
      setShowBreakdown(true)
    } catch (error) {
      console.error('Goal analysis failed:', error)
    } finally {
      setIsAnalyzing(false)
    }
  }

  const createTasksFromSteps = async () => {
    if (!breakdown?.steps || !currentUser) return

    try {
      const promises = breakdown.steps.map(step => 
        addDoc(collection(db, 'todos'), {
          text: step.title || step.description || step,
          completed: false,
          priority: 'medium',
          userId: currentUser.uid,
          createdAt: new Date().toISOString(),
          aiGenerated: true,
          goalRelated: goalInput
        })
      )

      await Promise.all(promises)
      setGoalInput('')
      setBreakdown(null)
      setShowBreakdown(false)
    } catch (error) {
      console.error('Failed to create tasks:', error)
    }
  }

  return (
    <div>
      <div className="flex items-center mb-4">
        <FaBullseye className="h-5 w-5 text-teal-500 mr-2" />
        <div>
          <h3 className="text-lg font-semibold text-gray-900 dark:text-white">AI Goal Breakdown</h3>
          <p className="text-sm text-gray-600 dark:text-gray-400">Break goals into actionable steps</p>
        </div>
        <FaRobot className="h-4 w-4 text-purple-500 ml-auto" />
      </div>

      <div className="space-y-4">
        <div className="flex space-x-2">
          <input
            type="text"
            value={goalInput}
            onChange={(e) => setGoalInput(e.target.value)}
            placeholder="Enter your goal (e.g., 'Learn React in 3 months')"
            className="flex-1 input-field text-sm"
            onKeyPress={(e) => e.key === 'Enter' && analyzeGoal()}
          />
          <button
            onClick={analyzeGoal}
            disabled={isAnalyzing || !goalInput.trim()}
            className="btn-primary px-4 py-2 disabled:opacity-50"
          >
            {isAnalyzing ? <FaSpinner className="animate-spin" /> : <FaRobot />}
          </button>
        </div>

        <AnimatePresence>
          {showBreakdown && breakdown && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              className="bg-white dark:bg-gray-800 rounded-lg p-4 border border-gray-200 dark:border-gray-700"
            >
              <div className="flex justify-between items-center mb-3">
                <h4 className="font-medium text-gray-900 dark:text-white">AI Breakdown</h4>
                <button
                  onClick={createTasksFromSteps}
                  className="btn-secondary text-sm px-3 py-1"
                >
                  <FaPlus className="mr-1" />
                  Create Tasks
                </button>
              </div>

              {breakdown.timeline && (
                <div className="mb-3 p-2 bg-blue-50 dark:bg-blue-900/20 rounded border border-blue-200 dark:border-blue-800">
                  <div className="flex items-center text-sm text-blue-700 dark:text-blue-300">
                    <FaClock className="mr-1" />
                    Timeline: {breakdown.timeline}
                  </div>
                </div>
              )}

              <div className="space-y-2">
                <h5 className="text-sm font-medium text-gray-700 dark:text-gray-300">Action Steps:</h5>
                {breakdown.steps?.map((step, index) => (
                  <div key={index} className="flex items-start space-x-2 p-2 bg-gray-50 dark:bg-gray-700 rounded">
                    <span className="flex-shrink-0 w-5 h-5 bg-teal-500 text-white text-xs rounded-full flex items-center justify-center mt-0.5">
                      {index + 1}
                    </span>
                    <div className="flex-1">
                      <p className="text-sm text-gray-900 dark:text-white">
                        {typeof step === 'string' ? step : step.title || step.description}
                      </p>
                      {step.duration && (
                        <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                          Duration: {step.duration}
                        </p>
                      )}
                    </div>
                  </div>
                ))}
              </div>

              {breakdown.metrics && breakdown.metrics.length > 0 && (
                <div className="mt-3">
                  <h5 className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Success Metrics:</h5>
                  <div className="space-y-1">
                    {breakdown.metrics.map((metric, index) => (
                      <div key={index} className="flex items-center text-sm text-gray-600 dark:text-gray-400">
                        <FaCheck className="mr-2 text-green-500" />
                        {metric}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  )
}

export default AIGoalBreakdown

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { FaLeaf, FaRobot, FaPlus, FaStar, FaSpinner, FaChartLine } from 'react-icons/fa'
import OpenRouterService from '../services/OpenRouterService'
import { useAuth } from '../context/AuthContext'
import { useHabits } from '../hooks/useFirestore'
import { addDoc, collection } from 'firebase/firestore'
import { db } from '../utils/firebase'

const AIHabitRecommendations = () => {
  const { currentUser } = useAuth()
  const { habits } = useHabits()
  const [isGenerating, setIsGenerating] = useState(false)
  const [recommendations, setRecommendations] = useState([])
  const [userProfile, setUserProfile] = useState({
    goals: [],
    lifestyle: 'balanced',
    experience: 'beginner'
  })
  const [showRecommendations, setShowRecommendations] = useState(false)

  const generateRecommendations = async () => {
    setIsGenerating(true)
    try {
      const profile = {
        ...userProfile,
        currentHabits: habits.map(h => ({ name: h.name, streak: h.streak, frequency: h.frequency })),
        completionRate: habits.length > 0 ? habits.reduce((acc, h) => acc + (h.streak > 0 ? 1 : 0), 0) / habits.length : 0
      }

      const result = await OpenRouterService.recommendHabits(profile, habits)
      setRecommendations(result.recommendations || [])
      setShowRecommendations(true)
    } catch (error) {
      console.error('Habit recommendation failed:', error)
    } finally {
      setIsGenerating(false)
    }
  }

  const addRecommendedHabit = async (habit) => {
    if (!currentUser) return

    try {
      await addDoc(collection(db, 'habits'), {
        name: habit.name || habit.title,
        description: habit.description || '',
        frequency: habit.frequency || 'daily',
        difficulty: habit.difficulty || 'easy',
        category: habit.category || 'general',
        userId: currentUser.uid,
        createdAt: new Date().toISOString(),
        aiRecommended: true,
        streak: 0,
        completions: []
      })
    } catch (error) {
      console.error('Failed to add habit:', error)
    }
  }

  const getDifficultyColor = (difficulty) => {
    switch (difficulty?.toLowerCase()) {
      case 'easy': return 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300'
      case 'medium': return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-300'
      case 'hard': return 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300'
      default: return 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300'
    }
  }

  return (
    <div>
      <div className="flex items-center mb-4">
        <FaLeaf className="h-5 w-5 text-green-500 mr-2" />
        <div>
          <h3 className="text-lg font-semibold text-gray-900 dark:text-white">AI Habit Coach</h3>
          <p className="text-sm text-gray-600 dark:text-gray-400">Personalized habit recommendations</p>
        </div>
        <FaRobot className="h-4 w-4 text-purple-500 ml-auto" />
      </div>

      <div className="space-y-4">
        {/* User Profile Setup */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
          <div>
            <label className="block text-xs font-medium text-gray-700 dark:text-gray-300 mb-1">
              Primary Goal
            </label>
            <select
              value={userProfile.goals[0] || ''}
              onChange={(e) => setUserProfile(prev => ({ ...prev, goals: [e.target.value] }))}
              className="w-full text-sm input-field"
            >
              <option value="">Select goal</option>
              <option value="health">Health & Fitness</option>
              <option value="productivity">Productivity</option>
              <option value="learning">Learning & Growth</option>
              <option value="mindfulness">Mindfulness</option>
              <option value="creativity">Creativity</option>
            </select>
          </div>

          <div>
            <label className="block text-xs font-medium text-gray-700 dark:text-gray-300 mb-1">
              Lifestyle
            </label>
            <select
              value={userProfile.lifestyle}
              onChange={(e) => setUserProfile(prev => ({ ...prev, lifestyle: e.target.value }))}
              className="w-full text-sm input-field"
            >
              <option value="busy">Busy Schedule</option>
              <option value="balanced">Balanced</option>
              <option value="flexible">Flexible</option>
            </select>
          </div>

          <div>
            <label className="block text-xs font-medium text-gray-700 dark:text-gray-300 mb-1">
              Experience
            </label>
            <select
              value={userProfile.experience}
              onChange={(e) => setUserProfile(prev => ({ ...prev, experience: e.target.value }))}
              className="w-full text-sm input-field"
            >
              <option value="beginner">Beginner</option>
              <option value="intermediate">Intermediate</option>
              <option value="advanced">Advanced</option>
            </select>
          </div>
        </div>

        <button
          onClick={generateRecommendations}
          disabled={isGenerating}
          className="w-full btn-primary disabled:opacity-50"
        >
          {isGenerating ? (
            <>
              <FaSpinner className="animate-spin mr-2" />
              Generating Recommendations...
            </>
          ) : (
            <>
              <FaRobot className="mr-2" />
              Get AI Recommendations
            </>
          )}
        </button>

        <AnimatePresence>
          {showRecommendations && recommendations.length > 0 && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              className="space-y-3"
            >
              <h4 className="font-medium text-gray-900 dark:text-white flex items-center">
                <FaStar className="mr-2 text-yellow-500" />
                Personalized Recommendations
              </h4>

              {recommendations.slice(0, 4).map((habit, index) => (
                <motion.div
                  key={index}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: index * 0.1 }}
                  className="bg-white dark:bg-gray-800 rounded-lg p-4 border border-gray-200 dark:border-gray-700"
                >
                  <div className="flex justify-between items-start mb-2">
                    <div className="flex-1">
                      <h5 className="font-medium text-gray-900 dark:text-white">
                        {habit.name || habit.title}
                      </h5>
                      <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">
                        {habit.description}
                      </p>
                    </div>
                    <button
                      onClick={() => addRecommendedHabit(habit)}
                      className="ml-2 btn-secondary text-sm px-3 py-1"
                    >
                      <FaPlus className="mr-1" />
                      Add
                    </button>
                  </div>

                  <div className="flex items-center space-x-2 mt-3">
                    <span className={`text-xs px-2 py-1 rounded-full ${getDifficultyColor(habit.difficulty)}`}>
                      {habit.difficulty || 'Easy'}
                    </span>
                    <span className="text-xs px-2 py-1 rounded-full bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300">
                      {habit.frequency || 'Daily'}
                    </span>
                    {habit.category && (
                      <span className="text-xs px-2 py-1 rounded-full bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-300">
                        {habit.category}
                      </span>
                    )}
                  </div>

                  {habit.benefits && (
                    <div className="mt-2">
                      <p className="text-xs text-gray-500 dark:text-gray-400">
                        <FaChartLine className="inline mr-1" />
                        Benefits: {habit.benefits}
                      </p>
                    </div>
                  )}

                  {habit.implementation && (
                    <div className="mt-2 p-2 bg-gray-50 dark:bg-gray-700 rounded text-xs text-gray-600 dark:text-gray-400">
                      💡 {habit.implementation}
                    </div>
                  )}
                </motion.div>
              ))}
            </motion.div>
          )}
        </AnimatePresence>

        {habits.length === 0 && (
          <div className="text-center py-4">
            <FaLeaf className="h-8 w-8 text-gray-400 mx-auto mb-2" />
