import { useState } from "react"
import { motion } from "framer-motion"
import { Download, FileText } from "lucide-react"
import { collection, query, where, getDocs } from "firebase/firestore"
import { db } from "../utils/firebase"
import { useAuth } from "../context/AuthContext"

const DataExport = () => {
  const { currentUser } = useAuth()
  const [loading, setLoading] = useState(false)

  const exportData = async () => {
    if (!currentUser) return

    setLoading(true)
    try {
      const collections = ["todos", "habits", "goals", "reflections"]
      const exportData = {
        exportDate: new Date().toISOString(),
        userId: currentUser.uid,
        userEmail: currentUser.email,
        data: {},
      }

      // Fetch data from each collection -->
      for (const collectionName of collections) {
        const q = query(collection(db, collectionName), where("userId", "==", currentUser.uid))

        const querySnapshot = await getDocs(q)
        const collectionData = []

        querySnapshot.forEach((doc) => {
          collectionData.push({ id: doc.id, ...doc.data() })
        })

        exportData.data[collectionName] = collectionData
      }

      // Creating and downloading JSON file -->
      const dataStr = JSON.stringify(exportData, null, 2)
      const dataBlob = new Blob([dataStr], { type: "application/json" })
      const url = URL.createObjectURL(dataBlob)

      const link = document.createElement("a")
      link.href = url
      link.download = `flownest-data-${new Date().toISOString().split("T")[0]}.json`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)

      URL.revokeObjectURL(url)
    } catch (error) {
      console.error("Error exporting data:", error)
      alert("Failed to export data. Please try again.")
    } finally {
      setLoading(false)
    }
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="bg-white dark:bg-gray-800 rounded-xl shadow-sm hover:shadow-md p-6 transition-all duration-300 border border-gray-100 dark:border-gray-700"
    >
      <div className="flex items-center mb-4">
        <FileText className="h-6 w-6 text-blue-500 mr-2" />
        <h2 className="text-xl font-semibold text-gray-900 dark:text-white">Data Export</h2>
      </div>

      <p className="text-gray-600 dark:text-gray-400 mb-6">
        Export all your FlowNest data including tasks, habits, goals, and reflections as a JSON file.
      </p>

      <button
        onClick={exportData}
        disabled={loading}
        className="bg-green-500 hover:bg-green-600 dark:bg-green-600 dark:hover:bg-green-700 text-white font-medium py-3 px-6 rounded-lg shadow-md hover:shadow-lg transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-green-500 focus:ring-offset-2 dark:focus:ring-offset-gray-800 flex items-center justify-center w-full disabled:opacity-50 disabled:cursor-not-allowed"
      >
        <Download size={18} className="mr-2" />
        {loading ? "Exporting..." : "Export My Data"}
      </button>

      <div className="mt-4 p-3 bg-blue-50 dark:bg-blue-900/20 rounded-lg border border-blue-200 dark:border-blue-800">
        <p className="text-sm text-blue-800 dark:text-blue-300">
          <strong>Note:</strong> The exported file will contain all your personal data. Keep it secure and only share it
          if necessary.
        </p>
      </div>
    </motion.div>
  )
}

export default DataExport

import { Component } from 'react'
import { motion } from 'framer-motion'
import { FaExclamationTriangle } from 'react-icons/fa'
import { MdRefresh } from "react-icons/md";

class ErrorBoundary extends Component {
  constructor(props) {
    super(props)
    this.state = { hasError: false, error: null, errorInfo: null }
  }

  static getDerivedStateFromError(error) {
    return { hasError: true }
  }

  componentDidCatch(error, errorInfo) {
    this.setState({
      error,
      errorInfo
    })

    // Log error to console in development
    if (import.meta.env.VITE_NODE_ENV === 'development') {
      console.error('Error caught by boundary:', error, errorInfo)
    }

    // In production, you would send this to an error reporting service
    // Example: Sentry.captureException(error, { extra: errorInfo })
  }

  handleReset = () => {
    this.setState({ hasError: false, error: null, errorInfo: null })
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-gray-900 p-4">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="max-w-md w-full bg-white dark:bg-gray-800 rounded-xl shadow-lg p-6 text-center border border-gray-200 dark:border-gray-700"
          >
            <div className="flex justify-center mb-4">
              <FaExclamationTriangle className="text-red-500 text-4xl" />
            </div>
            <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-2">
              Something went wrong
            </h2>
            <p className="text-gray-600 dark:text-gray-400 mb-6">
              We're sorry, but something unexpected happened. Please try refreshing the page.
            </p>
            <div className="space-y-3">
              <button
                onClick={this.handleReset}
                className="w-full btn-primary flex items-center justify-center"
              >
                <MdRefresh className="mr-2" />
                Try Again
              </button>
              <button
                onClick={() => window.location.reload()}
                className="w-full btn-secondary"
              >
                Refresh Page
              </button>
            </div>
            {import.meta.env.VITE_NODE_ENV === 'development' && this.state.error && (
              <details className="mt-4 text-left">
                <summary className="cursor-pointer text-sm text-gray-500 dark:text-gray-400">
                  Error Details (Development)
                </summary>
                <pre className="mt-2 text-xs bg-gray-100 dark:bg-gray-700 p-2 rounded overflow-auto">
                  {this.state.error.toString()}
                </pre>
              </details>
            )}
          </motion.div>
        </div>
      )
    }

    return this.props.children
  }
}

export default ErrorBoundary

import { useState, useEffect } from "react"
import { motion } from "framer-motion"
import { FaBrain, FaFire } from "react-icons/fa"
import { collection, query, where, onSnapshot } from "firebase/firestore"
import { db } from "../utils/firebase"
import { useAuth } from "../context/AuthContext"

const FocusScoreWidget = () => {
  const { currentUser } = useAuth()
  const [focusScore, setFocusScore] = useState(0)
  const [streak, setStreak] = useState(0)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (!currentUser) return

    const unsubscribes = []

    // Todos -->
    const todosQuery = query(collection(db, "todos"), where("userId", "==", currentUser.uid))
    const unsubscribeTodos = onSnapshot(todosQuery, (snapshot) => {
      calculateFocusScore(snapshot, "todos")
    })

    // Habits -->
    const habitsQuery = query(collection(db, "habits"), where("userId", "==", currentUser.uid))
    const unsubscribeHabits = onSnapshot(habitsQuery, (snapshot) => {
      calculateFocusScore(snapshot, "habits")
    })

    unsubscribes.push(unsubscribeTodos, unsubscribeHabits)
    setLoading(false)

    return () => {
      unsubscribes.forEach((unsubscribe) => unsubscribe())
    }
  }, [currentUser])

  const calculateFocusScore = (snapshot, type) => {
    let score = 0
    let currentStreak = 0

    if (type === "todos") {
      const todos = []
      snapshot.forEach((doc) => todos.push(doc.data()))

      const completedTodos = todos.filter((todo) => todo.completed)
      const totalTodos = todos.length

      if (totalTodos > 0) {
        score += Math.round((completedTodos.length / totalTodos) * 50)
      }

      // Calculate streak based on recent completions -->
      const recentCompletions = completedTodos.filter((todo) => {
        const completedDate = new Date(todo.completedAt || todo.createdAt)
        const daysDiff = Math.floor((new Date() - completedDate) / (1000 * 60 * 60 * 24))
        return daysDiff <= 7
      })
      currentStreak = Math.min(recentCompletions.length, 7)
    }

    if (type === "habits") {
      const habits = []
      snapshot.forEach((doc) => habits.push(doc.data()))

      let totalHabitDays = 0
      let completedHabitDays = 0

      habits.forEach((habit) => {
        if (habit.days && Array.isArray(habit.days)) {
          totalHabitDays += habit.days.length
          completedHabitDays += habit.days.filter((day) => day).length
        }
      })

      if (totalHabitDays > 0) {
        score += Math.round((completedHabitDays / totalHabitDays) * 50)
      }
    }

    setFocusScore((prev) => Math.min(Math.max(score, 0), 100))
    setStreak(currentStreak)
  }

  const getScoreColor = (score) => {
    if (score >= 80) return "text-green-500"
    if (score >= 60) return "text-blue-500"
    if (score >= 40) return "text-yellow-500"
    return "text-red-500"
  }

  const getScoreLabel = (score) => {
    if (score >= 80) return "Excellent"
    if (score >= 60) return "Good"
    if (score >= 40) return "Fair"
    return "Needs Work"
  }

  const getMotivationalMessage = (score) => {
    if (score >= 80) return "You're crushing it! 🚀"
    if (score >= 60) return "Great progress! Keep it up! 💪"
    if (score >= 40) return "You're getting there! 📈"
    return "Every step counts! 🌱"
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="card bg-gradient-to-br from-blue-50 to-indigo-50 dark:from-blue-900/20 dark:to-indigo-900/20 border-blue-200 dark:border-blue-800"
    >
      <div className="flex items-center mb-4">
        <FaBrain className="h-5 w-5 text-blue-500 mr-2" />
        <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Focus Score</h2>
      </div>

      {loading ? (
        <div className="animate-pulse text-center">
          <div className="w-20 h-20 bg-gray-200 dark:bg-gray-700 rounded-full mx-auto mb-4"></div>
          <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-1/2 mx-auto"></div>
        </div>
      ) : (
        <div className="text-center">
          <div className="relative w-20 h-20 mx-auto mb-4">
            <svg className="w-20 h-20 transform -rotate-90" viewBox="0 0 36 36">
              <path
                className="text-gray-200 dark:text-gray-700"
                stroke="currentColor"
                strokeWidth="3"
                fill="none"
                d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
              />
              <path
                className={getScoreColor(focusScore)}
                stroke="currentColor"
                strokeWidth="3"
                strokeLinecap="round"
                fill="none"
                strokeDasharray={`${focusScore}, 100`}
                d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
              />
            </svg>
            <div className="absolute inset-0 flex items-center justify-center">
              <span className={`text-2xl font-bold ${getScoreColor(focusScore)}`}>{focusScore}</span>
            </div>
          </div>

          <div className="space-y-2">
            <p className={`font-medium ${getScoreColor(focusScore)}`}>{getScoreLabel(focusScore)}</p>
            <p className="text-sm text-gray-600 dark:text-gray-400">{getMotivationalMessage(focusScore)}</p>

            {streak > 0 && (
              <div className="flex items-center justify-center space-x-1 mt-3 p-2 bg-orange-50 dark:bg-orange-900/20 rounded-lg">
                <FaFire className="text-orange-500" size={14} />
                <span className="text-sm font-medium text-orange-600 dark:text-orange-400">{streak} day streak!</span>
              </div>
            )}
          </div>
        </div>
      )}
    </motion.div>
  )
}

export default FocusScoreWidget

import { useState, useEffect } from "react"
import { motion } from "framer-motion"
import { FaPlus, FaTrash, FaEdit, FaSave, FaBullseye } from "react-icons/fa"
import { collection, addDoc, updateDoc, deleteDoc, doc, onSnapshot, query, where } from "firebase/firestore"
import { db } from "../utils/firebase"
import { useAuth } from "../context/AuthContext"

const GoalTracker = () => {
  const { currentUser } = useAuth()
  const [goals, setGoals] = useState([])
  const [newGoal, setNewGoal] = useState({
    title: "",
    description: "",
    targetValue: 100,
    currentValue: 0,
    type: "weekly",
    category: "personal",
  })
  const [editingGoal, setEditingGoal] = useState(null)
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    if (!currentUser) return

    const q = query(collection(db, "goals"), where("userId", "==", currentUser.uid))

    const unsubscribe = onSnapshot(q, (querySnapshot) => {
      const goalsData = []
      querySnapshot.forEach((doc) => {
        goalsData.push({ id: doc.id, ...doc.data() })
      })
      setGoals(goalsData)
    })

    return () => unsubscribe()
  }, [currentUser])

  const addGoal = async (e) => {
    e.preventDefault()
    if (!newGoal.title.trim()) return

    setLoading(true)
    try {
      await addDoc(collection(db, "goals"), {
        ...newGoal,
        userId: currentUser.uid,
        createdAt: new Date().toISOString(),
      })

      setNewGoal({
        title: "",
        description: "",
        targetValue: 100,
        currentValue: 0,
        type: "weekly",
        category: "personal",
      })
    } catch (error) {
      console.error("Error adding goal:", error)
    } finally {
      setLoading(false)
    }
  }

  const updateGoal = async (goalId, updates) => {
    try {
      await updateDoc(doc(db, "goals", goalId), updates)
    } catch (error) {
      console.error("Error updating goal:", error)
    }
  }

  const deleteGoal = async (goalId) => {
    try {
      await deleteDoc(doc(db, "goals", goalId))
    } catch (error) {
      console.error("Error deleting goal:", error)
    }
  }

  const getProgressPercentage = (current, target) => {
    return Math.min((current / target) * 100, 100)
  }

  const getProgressColor = (percentage) => {
    if (percentage >= 100) return "bg-green-500"
    if (percentage >= 75) return "bg-blue-500"
    if (percentage >= 50) return "bg-yellow-500"
    return "bg-gray-300 dark:bg-gray-600"
  }

  return (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="card h-fit">
      <div className="flex items-center mb-4">
        <FaBullseye className="h-5 w-5 text-green-500 mr-2" />
        <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Goal Tracker</h2>
      </div>

      {/* Add Goal Form */}
      <form onSubmit={addGoal} className="mb-6 space-y-3">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <input
            type="text"
            value={newGoal.title}
            onChange={(e) => setNewGoal({ ...newGoal, title: e.target.value })}
            placeholder="Goal title..."
            className="input-field"
            required
          />
          <select
            value={newGoal.type}
            onChange={(e) => setNewGoal({ ...newGoal, type: e.target.value })}
            className="input-field"
          >
            <option value="weekly">Weekly</option>
            <option value="monthly">Monthly</option>
          </select>
        </div>
        <textarea
          value={newGoal.description}
          onChange={(e) => setNewGoal({ ...newGoal, description: e.target.value })}
          placeholder="Goal description..."
          className="input-field min-h-[80px] resize-none"
        />
        <div className="grid grid-cols-2 gap-3">
          <input
            type="number"
            value={newGoal.targetValue}
            onChange={(e) => setNewGoal({ ...newGoal, targetValue: Number.parseInt(e.target.value) || 0 })}
            placeholder="Target value"
            className="input-field"
            min="1"
          />
          <button type="submit" disabled={loading} className="btn-primary flex items-center justify-center">
            <FaPlus size={16} className="mr-2" />
            {loading ? "Adding..." : "Add Goal"}
          </button>
        </div>
      </form>

      {/* Goals List */}
      <div className="space-y-4 max-h-64 overflow-y-auto">
        {goals.length > 0 ? (
          goals.map((goal) => (
            <div
              key={goal.id}
              className="p-4 bg-gray-50 dark:bg-gray-700 rounded-lg border border-gray-100 dark:border-gray-600"
            >
              <div className="flex justify-between items-start mb-3">
                <div className="flex-1 min-w-0">
                  <h3 className="font-medium text-gray-900 dark:text-white truncate">{goal.title}</h3>
                  <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">{goal.description}</p>
                  <span
                    className={`inline-block px-2 py-1 text-xs rounded-full mt-2 ${
                      goal.type === "weekly"
                        ? "bg-blue-100 dark:bg-blue-900/30 text-blue-800 dark:text-blue-300"
                        : "bg-purple-100 dark:bg-purple-900/30 text-purple-800 dark:text-purple-300"
                    }`}
                  >
                    {goal.type}
                  </span>
                </div>
                <div className="flex space-x-2 ml-3">
                  <button
                    onClick={() => setEditingGoal(goal)}
                    className="p-1 text-gray-500 dark:text-gray-400 hover:text-blue-500 dark:hover:text-blue-400 transition-colors"
                  >
                    <FaEdit size={14} />
                  </button>
                  <button
                    onClick={() => deleteGoal(goal.id)}
                    className="p-1 text-gray-500 dark:text-gray-400 hover:text-red-500 dark:hover:text-red-400 transition-colors"
                  >
                    <FaTrash size={14} />
                  </button>
                </div>
              </div>

              {/* Progress Bar */}
              <div className="mb-3">
                <div className="flex justify-between text-sm text-gray-600 dark:text-gray-400 mb-1">
                  <span>Progress</span>
                  <span>
                    {goal.currentValue} / {goal.targetValue}
                  </span>
                </div>
                <div className="w-full bg-gray-200 dark:bg-gray-600 rounded-full h-2">
                  <div
                    className={`h-2 rounded-full transition-all duration-300 ${getProgressColor(getProgressPercentage(goal.currentValue, goal.targetValue))}`}
                    style={{ width: `${getProgressPercentage(goal.currentValue, goal.targetValue)}%` }}
                  ></div>
                </div>
                <div className="text-right text-sm text-gray-600 dark:text-gray-400 mt-1">
                  {getProgressPercentage(goal.currentValue, goal.targetValue).toFixed(1)}%
                </div>
              </div>

              {/* Update Progress */}
              <div className="flex gap-2">
                <input
                  type="number"
                  placeholder="Update progress"
                  className="input-field flex-grow text-sm"
                  onKeyPress={(e) => {
                    if (e.key === "Enter") {
                      const value = Number.parseInt(e.target.value) || 0
                      updateGoal(goal.id, { currentValue: value })
                      e.target.value = ""
                    }
                  }}
                />
                <button
                  onClick={() => {
                    const input = document.querySelector(`input[placeholder="Update progress"]`)
                    const value = Number.parseInt(input.value) || 0
                    updateGoal(goal.id, { currentValue: value })
                    input.value = ""
                  }}
                  className="btn-primary px-3 py-2"
                >
                  <FaSave size={14} />
                </button>
              </div>
            </div>
          ))
        ) : (
          <div className="text-center py-8">
            <FaBullseye className="h-8 w-8 text-gray-300 dark:text-gray-600 mx-auto mb-2" />
            <p className="text-gray-500 dark:text-gray-400 text-sm">No goals yet. Set your first goal above!</p>
          </div>
        )}
      </div>
    </motion.div>
  )
}

export default GoalTracker

