import { useState, useEffect } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { FaWifi } from "react-icons/fa"

/**
 * OfflineIndicator — shows a banner when the user loses internet connectivity.
 * Automatically hides when the connection is restored.
 */
export const OfflineIndicator = () => {
  const [isOffline, setIsOffline] = useState(!navigator.onLine)

  useEffect(() => {
    const handleOnline = () => setIsOffline(false)
    const handleOffline = () => setIsOffline(true)

    window.addEventListener("online", handleOnline)
    window.addEventListener("offline", handleOffline)

    return () => {
      window.removeEventListener("online", handleOnline)
      window.removeEventListener("offline", handleOffline)
    }
  }, [])

  return (
    <AnimatePresence>
      {isOffline && (
        <motion.div
          initial={{ y: -50, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: -50, opacity: 0 }}
          transition={{ type: "spring", stiffness: 300, damping: 25 }}
          className="fixed top-0 left-0 right-0 z-50 bg-yellow-500 text-yellow-900 px-4 py-2 text-center text-sm font-medium shadow-md flex items-center justify-center space-x-2"
        >
          <FaWifi className="h-4 w-4 animate-pulse" />
          <span>
            You are offline. Changes will sync when you reconnect.
          </span>
        </motion.div>
      )}
    </AnimatePresence>
  )
}

export default OfflineIndicator

import { useState, useEffect, useRef, useCallback } from "react"
import { FaPlay, FaPause, FaRedo } from "react-icons/fa"
import { motion } from "framer-motion"

const PomodoroWidget = () => {
  const [timeLeft, setTimeLeft] = useState(25 * 60) // 25 minutes in seconds
  const [isActive, setIsActive] = useState(false)
  const [mode, setMode] = useState("pomodoro") // pomodoro, shortBreak, longBreak
  const intervalRef = useRef(null)
  const [selectedSound, setSelectedSound] = useState("none")
  const [volume, setVolume] = useState(0.5)
  const audioRef = useRef(null)

  const handleTimerCompletion = useCallback(() => {
    if (typeof window !== "undefined" && "Notification" in window) {
      if (Notification.permission === "granted") {
        new Notification("Pomodoro Timer", {
          body: "Time's up!",
          icon: "/favicon.ico",
        })
      } else if (Notification.permission !== "denied") {
        Notification.requestPermission().then((permission) => {
          if (permission === "granted") {
            new Notification("Pomodoro Timer", {
              body: "Time's up!",
              icon: "/favicon.ico",
            })
          }
        })
      }
    }
    if (selectedSound !== "none" && audioRef.current) {
      audioRef.current.play()
    }
  }, [selectedSound])

  useEffect(() => {
    if (isActive) {
      intervalRef.current = setInterval(() => {
        setTimeLeft((prevTime) => {
          if (prevTime <= 1) {
            clearInterval(intervalRef.current)
            setIsActive(false)
            handleTimerCompletion()
            return 0
          }
          return prevTime - 1
        })
      }, 1000)
    } else {
      clearInterval(intervalRef.current)
    }

    return () => clearInterval(intervalRef.current)
  }, [isActive, handleTimerCompletion])

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.volume = volume
    }
  }, [volume])

  const toggleTimer = () => {
    setIsActive(!isActive)
  }

  const resetTimer = () => {
    clearInterval(intervalRef.current)
    setIsActive(false)

    switch (mode) {
      case "pomodoro":
        setTimeLeft(25 * 60)
        break
      case "shortBreak":
        setTimeLeft(5 * 60)
        break
      case "longBreak":
        setTimeLeft(15 * 60)
        break
      default:
        setTimeLeft(25 * 60)
    }
  }

  const changeMode = (newMode) => {
    setMode(newMode)
    setIsActive(false)

    switch (newMode) {
      case "pomodoro":
        setTimeLeft(25 * 60)
        break
      case "shortBreak":
        setTimeLeft(5 * 60)
        break
      case "longBreak":
        setTimeLeft(15 * 60)
        break
      default:
        setTimeLeft(25 * 60)
    }
  }

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60)
    const secs = seconds % 60
    return `${mins.toString().padStart(2, "0")}:${secs.toString().padStart(2, "0")}`
  }

  const handleSoundChange = (e) => {
    setSelectedSound(e.target.value)
    if (audioRef.current) {
      audioRef.current.pause()
      audioRef.current.currentTime = 0
    }
  }

  return (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="card h-fit">
      <h2 className="widget-title">Pomodoro Timer</h2>

      <div className="flex justify-center mb-6">
        <div className="flex space-x-1 bg-gray-100 dark:bg-gray-700 p-1 rounded-lg">
          <button
            onClick={() => changeMode("pomodoro")}
            className={`px-3 py-2 rounded-md text-xs font-medium transition-colors ${
              mode === "pomodoro"
                ? "bg-white dark:bg-gray-600 shadow-sm text-gray-900 dark:text-white"
                : "text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600"
            }`}
          >
            Pomodoro
          </button>
          <button
            onClick={() => changeMode("shortBreak")}
            className={`px-3 py-2 rounded-md text-xs font-medium transition-colors ${
              mode === "shortBreak"
                ? "bg-white dark:bg-gray-600 shadow-sm text-gray-900 dark:text-white"
                : "text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600"
            }`}
          >
            Short Break
          </button>
          <button
            onClick={() => changeMode("longBreak")}
            className={`px-3 py-2 rounded-md text-xs font-medium transition-colors ${
              mode === "longBreak"
                ? "bg-white dark:bg-gray-600 shadow-sm text-gray-900 dark:text-white"
                : "text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600"
            }`}
          >
            Long Break
          </button>
        </div>
      </div>

      <div className="flex justify-center mb-6">
        <div className="text-4xl sm:text-5xl font-bold bg-blue-50 dark:bg-blue-900/20 px-6 py-4 rounded-xl text-blue-600 dark:text-blue-400 border border-blue-200 dark:border-blue-800">
          {formatTime(timeLeft)}
        </div>
      </div>

      <div className="space-y-4 mb-6">
        <div className="flex items-center justify-between">
          <label htmlFor="sound" className="text-sm font-medium text-gray-700 dark:text-gray-300">
            Ambient Sound:
          </label>
          <select id="sound" value={selectedSound} onChange={handleSoundChange} className="input-field text-sm w-32">
            <option value="none">None</option>
            <option value="rain">Rain</option>
            <option value="cafe">Cafe</option>
            <option value="whiteNoise">White Noise</option>
          </select>
        </div>

        <div className="flex items-center justify-between">
          <label htmlFor="volume" className="text-sm font-medium text-gray-700 dark:text-gray-300">
            Volume:
          </label>
          <input
            type="range"
            id="volume"
            min="0"
            max="1"
            step="0.01"
            value={volume}
            onChange={(e) => setVolume(Number.parseFloat(e.target.value))}
            className="w-24"
          />
        </div>
      </div>

      <audio
        ref={audioRef}
        loop
        src={
          selectedSound === "rain"
            ? "/sounds/rain.mp3"
            : selectedSound === "cafe"
              ? "/sounds/cafe.mp3"
              : selectedSound === "whiteNoise"
                ? "/sounds/whiteNoise.mp3"
                : null
        }
      />

      <div className="flex justify-center space-x-3">
        <button onClick={toggleTimer} className="btn-primary flex items-center justify-center px-6">
          {isActive ? <FaPause size={16} /> : <FaPlay size={16} />}
          <span className="ml-2">{isActive ? "Pause" : "Start"}</span>
        </button>
        <button
          onClick={resetTimer}
          className="bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-300 font-medium py-3 px-6 rounded-lg shadow-md transition-all duration-300 flex items-center"
        >
          <FaRedo size={16} />
          <span className="ml-2">Reset</span>
        </button>
      </div>
    </motion.div>
  )
}

export default PomodoroWidget

import { useState, useEffect } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { FaQuoteLeft, FaChevronLeft, FaChevronRight, FaSync, FaMagic, FaRobot } from "react-icons/fa"
import OpenRouterService from "../services/OpenRouterService"
import { LoadingSpinner } from "./Loading"
import { useAuth } from "../context/AuthContext"

const QuoteCarousel = () => {
    const [currentQuote, setCurrentQuote] = useState(0)
  const [isAutoPlay, setIsAutoPlay] = useState(true)
  const [isRefreshing, setIsRefreshing] = useState(false)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)
  const [quotes, setQuotes] = useState([])
  const [isAIEnabled, setIsAIEnabled] = useState(false)

  useEffect(() => {
    loadInitialQuotes()
  }, [])

  const loadInitialQuotes = async () => {
    try {
      setLoading(true)
      setError(null)

      // Check if OpenRouter is available
      const openRouterAvailable = import.meta.env.VITE_OPENROUTER_API_KEY && 
                                  import.meta.env.VITE_OPENROUTER_API_KEY !== 'your_openrouter_api_key_here'

      setIsAIEnabled(openRouterAvailable)

      if (openRouterAvailable) {
        // Generate AI-powered personalized quote
        const userContext = {
          mood: 'motivated',
          goals: 'productivity and growth',
          recentActivity: 'working on personal development'
        }

        const aiQuote = await OpenRouterService.generateMotivationalQuote(userContext)

        // Fallback quotes
        const fallbackQuotes = [
          {
            text: "The future depends on what you do today.",
            author: "Mahatma Gandhi",
          },
          {
            text: "Success is not final, failure is not fatal: it is the courage to continue that counts.",
            author: "Winston Churchill",
          },
          {
            text: "The only way to do great work is to love what you do.",
            author: "Steve Jobs",
          }
        ]

        setQuotes([aiQuote, ...fallbackQuotes])
      } else {
        // Use fallback quotes only
        const fallbackQuotes = [
          {
            text: "The way to get started is to quit talking and begin doing.",
            author: "Walt Disney",
          },
          {
            text: "Don't let yesterday take up too much of today.",
            author: "Will Rogers",
          },
          {
            text: "You learn more from failure than from success.",
            author: "Unknown",
          },
          {
            text: "The future depends on what you do today.",
            author: "Mahatma Gandhi",
          }
        ]
        setQuotes(fallbackQuotes)
      }
    } catch (err) {
      setError(err.message)
      // Load fallback quotes on error
      const fallbackQuotes = [
        {
          text: "Every moment is a fresh beginning.",
          author: "T.S. Eliot",
        },
        {
          text: "The only impossible journey is the one you never begin.",
          author: "Tony Robbins",
        }
      ]
      setQuotes(fallbackQuotes)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    if (isAutoPlay && !loading && quotes.length > 0) {
      const interval = setInterval(() => {
        setCurrentQuote((prev) => (prev + 1) % quotes.length)
      }, 6000) // Slower for AI quotes
      return () => clearInterval(interval)
    }
  }, [isAutoPlay, quotes.length, loading])

  const nextQuote = () => {
    setCurrentQuote((prev) => (prev + 1) % quotes.length)
  }

  const prevQuote = () => {
    setCurrentQuote((prev) => (prev - 1 + quotes.length) % quotes.length)
  }

  const goToQuote = (index) => {
    setCurrentQuote(index)
  }

  const refreshQuotes = async () => {
    if (isRefreshing) return

    try {
      setIsRefreshing(true)
      setError(null)

      if (isAIEnabled) {
        // Generate new AI quotes with different contexts
        const contexts = [
          { mood: 'focused', goals: 'achieving excellence', recentActivity: 'deep work' },
          { mood: 'energetic', goals: 'personal growth', recentActivity: 'learning new skills' },
          { mood: 'determined', goals: 'overcoming challenges', recentActivity: 'problem solving' }
        ]

        const newQuotes = await Promise.all(
          contexts.map(context => OpenRouterService.generateMotivationalQuote(context))
        )

        setQuotes(prev => [...newQuotes, ...prev.slice(3)])
      } else {
        // Just shuffle existing quotes
        setQuotes(prev => [...prev].sort(() => Math.random() - 0.5))
      }

      setCurrentQuote(0)
    } catch (err) {
      setError(err.message)
    } finally {
      setIsRefreshing(false)
    }
  }

  const retryLoad = () => {
    loadInitialQuotes()
  }

  if (loading) {
    return (
      <section className="py-12 bg-gradient-to-br from-blue-50 to-indigo-100 dark:from-blue-900/20 dark:to-indigo-900/30 rounded-2xl border border-blue-200 dark:border-blue-800 relative">
        <div className="max-w-4xl mx-auto px-6">
          <div className="text-center mb-8">
            <div className="flex items-center justify-center mb-4">
              <FaQuoteLeft className="text-blue-500 text-2xl mr-3" />
              <h2 className="text-2xl font-bold text-gray-900 dark:text-white">AI-Powered Inspiration</h2>
            </div>
            <p className="text-gray-600 dark:text-gray-300">Generating personalized motivation...</p>
          </div>
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg p-6 border border-gray-100 dark:border-gray-700 min-h-[200px] flex items-center justify-center">
            <LoadingSpinner size="lg" />
          </div>
        </div>
      </section>
    )
  }

  if (error) {
    return (
      <section className="py-12 bg-gradient-to-br from-blue-50 to-indigo-100 dark:from-blue-900/20 dark:to-indigo-900/30 rounded-2xl border border-blue-200 dark:border-blue-800 relative">
        <div className="max-w-4xl mx-auto px-6">
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg p-6 border border-gray-100 dark:border-gray-700 min-h-[200px] flex flex-col items-center justify-center">
            <p className="text-red-600 dark:text-red-400 mb-4">Failed to load quotes</p>
            <button
              onClick={retryLoad}
              className="bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded-lg transition-colors duration-300"
            >
              Retry
            </button>
          </div>
        </div>
      </section>
    )
  }

  return (
    <section className="py-12 bg-gradient-to-br from-blue-50 to-indigo-100 dark:from-blue-900/20 dark:to-indigo-900/30 rounded-2xl border border-blue-200 dark:border-blue-800 relative">
      <div className="max-w-4xl mx-auto px-6">
        <div className="text-center mb-8">
          <div className="flex items-center justify-center mb-4">
            <FaQuoteLeft className="text-blue-500 text-2xl mr-3" />
            <h2 className="text-2xl font-bold text-gray-900 dark:text-white">AI-Powered Inspiration</h2>
            {isAIEnabled && (
              <FaRobot className="text-purple-500 text-lg ml-2" title="Powered by GPT-3.5 Turbo" />
            )}
          </div>
          <p className="text-gray-600 dark:text-gray-300">
            {isAIEnabled ? 'Personalized motivation powered by advanced AI' : 'Curated wisdom to fuel your productivity'}
          </p>
        </div>

        {/* Refresh Button */}
        <button
          onClick={refreshQuotes}
          disabled={isRefreshing}
          className="absolute top-4 right-4 p-2 rounded-full bg-white dark:bg-gray-800 shadow-md hover:shadow-lg transition-all duration-300 text-gray-600 dark:text-gray-300 hover:text-blue-600 dark:hover:text-blue-400 disabled:opacity-50"
          title={isAIEnabled ? 'Generate new AI quotes' : 'Refresh quotes'}
        >
          {isRefreshing ? (
            <LoadingSpinner size="sm" />
          ) : isAIEnabled ? (
            <FaRobot size={16} />
          ) : (
            <FaSync size={16} />
          )}
        </button>

        <div className="relative">
          <div
            className="flex items-center justify-center mb-6"
            onMouseEnter={() => setIsAutoPlay(false)}
            onMouseLeave={() => setIsAutoPlay(true)}
