          </div>
        </div>
      </div>
    </section>
  )
}

export default QuoteCarousel

import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { FaHistory, FaCheckCircle, FaClock } from "react-icons/fa";
import { BiTargetLock } from "react-icons/bi";
import { collection, query, where, orderBy, limit, onSnapshot } from "firebase/firestore";
import { db } from "../utils/firebase";
import { useAuth } from "../context/AuthContext";

const RecentActivityWidget = () => {
  const { currentUser } = useAuth();
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!currentUser) return;

    const collections = [
      { name: "todos", icon: FaCheckCircle, color: "text-green-500" },
      { name: "goals", icon: BiTargetLock, color: "text-blue-500" },
      { name: "reflections", icon: FaClock, color: "text-purple-500" },
    ];

    const unsubscribes = [];
    let allActivities = [];

    collections.forEach(({ name, icon, color }) => {
      const q = query(
        collection(db, name),
        where("userId", "==", currentUser.uid),
        orderBy("createdAt", "desc"),
        limit(3)
      );

      const unsubscribe = onSnapshot(q, (querySnapshot) => {
        const collectionActivities = [];
        querySnapshot.forEach((doc) => {
          const data = doc.data();
          collectionActivities.push({
            id: doc.id,
            type: name,
            title: data.title || data.text || data.name || "Activity",
            timestamp: data.createdAt,
            icon,
            color,
          });
        });

        // Update activities for this collection -->
        allActivities = allActivities.filter((activity) => activity.type !== name);
        allActivities = [...allActivities, ...collectionActivities];

        // Sort by timestamp and take latest 5 activities -->
        allActivities.sort((a, b) => {
          const aTime = a.timestamp ? new Date(a.timestamp) : new Date(0);
          const bTime = b.timestamp ? new Date(b.timestamp) : new Date(0);
          return bTime - aTime;
        });

        setActivities(allActivities.slice(0, 5));
        setLoading(false);
      });

      unsubscribes.push(unsubscribe);
    });

    return () => {
      unsubscribes.forEach((unsubscribe) => unsubscribe());
    };
  }, [currentUser]);

  const formatTimeAgo = (timestamp) => {
    if (!timestamp) return "Recently";

    const date = new Date(timestamp);
    const now = new Date();
    const diffInMinutes = Math.floor((now - date) / (1000 * 60));

    if (diffInMinutes < 1) return "Just now";
    if (diffInMinutes < 60) return `${diffInMinutes}m ago`;
    if (diffInMinutes < 1440) return `${Math.floor(diffInMinutes / 60)}h ago`;
    return `${Math.floor(diffInMinutes / 1440)}d ago`;
  };

  const getTypeLabel = (type) => {
    switch (type) {
      case "todos":
        return "Task";
      case "goals":
        return "Goal";
      case "reflections":
        return "Reflection";
      default:
        return "Activity";
    }
  };

  return (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="card">
      <div className="flex items-center mb-4">
        <FaHistory className="h-5 w-5 text-gray-500 dark:text-gray-400 mr-2" />
        <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Recent Activity</h2>
      </div>

      {loading ? (
        <div className="space-y-3">
          {[...Array(3)].map((_, i) => (
            <div key={i} className="animate-pulse flex items-center space-x-3">
              <div className="w-8 h-8 bg-gray-200 dark:bg-gray-700 rounded-full"></div>
              <div className="flex-1">
                <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-3/4 mb-1"></div>
                <div className="h-3 bg-gray-200 dark:bg-gray-700 rounded w-1/2"></div>
              </div>
            </div>
          ))}
        </div>
      ) : activities.length > 0 ? (
        <div className="space-y-3">
          {activities.map((activity) => {
            const IconComponent = activity.icon;
            return (
              <div
                key={`${activity.type}-${activity.id}`}
                className="flex items-center space-x-3 p-2 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors"
              >
                <div className={`p-2 rounded-full bg-gray-100 dark:bg-gray-800 ${activity.color}`}>
                  <IconComponent size={14} />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-gray-900 dark:text-white truncate">{activity.title}</p>
                  <p className="text-xs text-gray-500 dark:text-gray-400">
                    {getTypeLabel(activity.type)} • {formatTimeAgo(activity.timestamp)}
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="text-center py-6">
          <FaHistory className="h-8 w-8 text-gray-300 dark:text-gray-600 mx-auto mb-2" />
          <p className="text-gray-500 dark:text-gray-400 text-sm">No recent activity</p>
        </div>
      )}
    </motion.div>
  );
};

export default RecentActivityWidget;

import { useState, useEffect } from "react"
import { motion } from "framer-motion"
import { FaClock, FaPlus, FaTrash } from "react-icons/fa"

const TimeBlockingWidget = () => {
  const [timeBlocks, setTimeBlocks] = useState([])
  const [newBlock, setNewBlock] = useState({
    title: "",
    startTime: "",
    endTime: "",
    color: "blue",
  })
  const [showForm, setShowForm] = useState(false)

  const colors = [
    {
      name: "blue",
      bg: "bg-blue-100 dark:bg-blue-900/30",
      text: "text-blue-800 dark:text-blue-300",
      border: "border-blue-200 dark:border-blue-800",
    },
    {
      name: "green",
      bg: "bg-green-100 dark:bg-green-900/30",
      text: "text-green-800 dark:text-green-300",
      border: "border-green-200 dark:border-green-800",
    },
    {
      name: "purple",
      bg: "bg-purple-100 dark:bg-purple-900/30",
      text: "text-purple-800 dark:text-purple-300",
      border: "border-purple-200 dark:border-purple-800",
    },
    {
      name: "orange",
      bg: "bg-orange-100 dark:bg-orange-900/30",
      text: "text-orange-800 dark:text-orange-300",
      border: "border-orange-200 dark:border-orange-800",
    },
  ]

  useEffect(() => {
    const saved = localStorage.getItem("timeBlocks")
    const savedDate = localStorage.getItem("timeBlocksDate")
    const today = new Date().toDateString()

    if (saved && savedDate === today) {
      setTimeBlocks(JSON.parse(saved))
    } else {
      setTimeBlocks([])
      localStorage.setItem("timeBlocksDate", today)
    }
  }, [])

  const saveTimeBlocks = (blocks) => {
    setTimeBlocks(blocks)
    localStorage.setItem("timeBlocks", JSON.stringify(blocks))
    localStorage.setItem("timeBlocksDate", new Date().toDateString())
  }

  const addTimeBlock = (e) => {
    e.preventDefault()
    if (!newBlock.title || !newBlock.startTime || !newBlock.endTime) return

    const block = {
      id: Date.now(),
      ...newBlock,
    }

    const updatedBlocks = [...timeBlocks, block].sort((a, b) => a.startTime.localeCompare(b.startTime))
    saveTimeBlocks(updatedBlocks)

    setNewBlock({ title: "", startTime: "", endTime: "", color: "blue" })
    setShowForm(false)
  }

  const deleteTimeBlock = (id) => {
    const updatedBlocks = timeBlocks.filter((block) => block.id !== id)
    saveTimeBlocks(updatedBlocks)
  }

  const formatTime = (time) => {
    const [hours, minutes] = time.split(":")
    const hour = Number.parseInt(hours)
    const ampm = hour >= 12 ? "PM" : "AM"
    const displayHour = hour % 12 || 12
    return `${displayHour}:${minutes} ${ampm}`
  }

  const getColorClasses = (colorName) => {
    return colors.find((c) => c.name === colorName) || colors[0]
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="bg-gradient-to-br from-slate-50 to-gray-50 dark:from-slate-900/20 dark:to-gray-900/20 rounded-xl shadow-sm hover:shadow-md p-6 transition-all duration-300 border border-slate-200 dark:border-slate-800 h-full"
    >
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center">
          <FaClock className="h-5 w-5 text-slate-500 mr-2" />
          <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Time Blocking</h2>
        </div>
        <button
          onClick={() => setShowForm(!showForm)}
          className="p-2 text-slate-500 hover:text-slate-600 dark:hover:text-slate-400 transition-colors"
        >
          <FaPlus size={14} />
        </button>
      </div>

      {showForm && (
        <motion.form
          initial={{ opacity: 0, height: 0 }}
          animate={{ opacity: 1, height: "auto" }}
          exit={{ opacity: 0, height: 0 }}
          onSubmit={addTimeBlock}
          className="mb-4 p-3 bg-gray-50 dark:bg-gray-800 rounded-lg space-y-3"
        >
          <input
            type="text"
            value={newBlock.title}
            onChange={(e) => setNewBlock({ ...newBlock, title: e.target.value })}
            placeholder="Activity title..."
            className="input-field text-sm"
            required
          />
          <div className="grid grid-cols-2 gap-2">
            <input
              type="time"
              value={newBlock.startTime}
              onChange={(e) => setNewBlock({ ...newBlock, startTime: e.target.value })}
              className="input-field text-sm"
              required
            />
            <input
              type="time"
              value={newBlock.endTime}
              onChange={(e) => setNewBlock({ ...newBlock, endTime: e.target.value })}
              className="input-field text-sm"
              required
            />
          </div>
          <div className="flex space-x-2">
            {colors.map((color) => (
              <button
                key={color.name}
                type="button"
                onClick={() => setNewBlock({ ...newBlock, color: color.name })}
                className={`w-6 h-6 rounded-full ${color.bg} ${color.border} border-2 ${
                  newBlock.color === color.name ? "ring-2 ring-gray-400" : ""
                }`}
              />
            ))}
          </div>
          <div className="flex space-x-2">
            <button type="submit" className="btn-primary text-sm flex-1">
              Add Block
            </button>
            <button
              type="button"
              onClick={() => setShowForm(false)}
              className="px-3 py-1 text-sm text-gray-600 dark:text-gray-400 hover:text-gray-800 dark:hover:text-gray-200"
            >
              Cancel
            </button>
          </div>
        </motion.form>
      )}

      <div className="space-y-2 max-h-64 overflow-y-auto">
        {timeBlocks.length > 0 ? (
          timeBlocks.map((block) => {
            const colorClasses = getColorClasses(block.color)
            return (
              <div
                key={block.id}
                className={`p-3 rounded-lg ${colorClasses.bg} ${colorClasses.border} border flex items-center justify-between`}
              >
                <div>
                  <h4 className={`font-medium ${colorClasses.text} text-sm`}>{block.title}</h4>
                  <p className={`text-xs ${colorClasses.text} opacity-75`}>
                    {formatTime(block.startTime)} - {formatTime(block.endTime)}
                  </p>
                </div>
                <button
                  onClick={() => deleteTimeBlock(block.id)}
                  className="text-gray-400 hover:text-red-500 dark:hover:text-red-400 transition-colors"
                >
                  <FaTrash size={12} />
                </button>
              </div>
            )
          })
        ) : (
          <div className="text-center py-6">
            <FaClock className="h-8 w-8 text-gray-300 dark:text-gray-600 mx-auto mb-2" />
            <p className="text-gray-500 dark:text-gray-400 text-sm">No time blocks for today</p>
          </div>
        )}
      </div>
    </motion.div>
  )
}

export default TimeBlockingWidget

import { useState } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { FaPlus, FaTrash, FaExclamationCircle } from "react-icons/fa"
import { useTodos } from "../hooks/useFirestore"
import { LoadingSpinner } from "./Loading"

const TodoWidget = () => {
  const { todos, loading, error, addTodo, updateTodo, deleteTodo } = useTodos()
  const [newTask, setNewTask] = useState("")
  const [priority, setPriority] = useState("medium")
  const [isSubmitting, setIsSubmitting] = useState(false)

  const handleAddTask = async (e) => {
    e.preventDefault()
    if (!newTask.trim() || isSubmitting) return

    try {
      setIsSubmitting(true)
      await addTodo({
        text: newTask.trim(),
        completed: false,
        priority,
        order: priority === "high" ? 1 : priority === "medium" ? 2 : 3,
      })
      setNewTask("")
      setPriority("medium")
    } catch (error) {
      console.error("Error adding task:", error)
    } finally {
      setIsSubmitting(false)
    }
  }

  const handleToggleComplete = async (id) => {
    try {
      const task = todos.find((task) => task.id === id)
      if (task) {
        await updateTodo(id, { completed: !task.completed })
      }
    } catch (error) {
      console.error("Error updating task:", error)
    }
  }

  const handleDeleteTask = async (id) => {
    try {
      await deleteTodo(id)
    } catch (error) {
      console.error("Error deleting task:", error)
    }
  }

  const getPriorityColor = (priority) => {
    switch (priority) {
      case "high":
        return "bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-300"
      case "medium":
        return "bg-yellow-100 dark:bg-yellow-900/30 text-yellow-800 dark:text-yellow-300"
      case "low":
        return "bg-green-100 dark:bg-green-900/30 text-green-800 dark:text-green-300"
      default:
        return "bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-300"
    }
  }

  if (loading) {
    return (
      <div className="card h-fit">
        <h2 className="widget-title">To-Do</h2>
        <div className="flex justify-center py-8">
          <LoadingSpinner />
        </div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="card h-fit">
        <h2 className="widget-title">To-Do</h2>
        <div className="text-center py-8">
          <FaExclamationCircle className="text-red-500 text-2xl mx-auto mb-2" />
          <p className="text-red-600 dark:text-red-400 text-sm">Failed to load tasks</p>
        </div>
      </div>
    )
  }

  return (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="card h-fit">
      <h2 className="widget-title">To-Do</h2>

      <form onSubmit={handleAddTask} className="mb-4 space-y-3">
        <input
          type="text"
          value={newTask}
          onChange={(e) => setNewTask(e.target.value)}
          placeholder="Add a new task..."
          className="input-field"
          disabled={isSubmitting}
        />
        <div className="flex gap-2">
          <select 
            value={priority} 
            onChange={(e) => setPriority(e.target.value)} 
            className="input-field flex-1"
            disabled={isSubmitting}
          >
            <option value="high">High</option>
            <option value="medium">Medium</option>
            <option value="low">Low</option>
          </select>
          <button 
            type="submit" 
            className="btn-primary px-4 py-2 disabled:opacity-50 disabled:cursor-not-allowed"
            disabled={isSubmitting || !newTask.trim()}
          >
            {isSubmitting ? <LoadingSpinner size="sm" /> : <FaPlus size={16} />}
          </button>
        </div>
      </form>

      <div className="space-y-2 max-h-64 overflow-y-auto">
        <AnimatePresence>
          {todos.map((task) => (
            <motion.div
              key={task.id}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 20 }}
              className="flex items-center justify-between p-3 bg-gray-50 dark:bg-gray-700 border border-gray-100 dark:border-gray-600 rounded-lg"
            >
              <div className="flex items-center gap-3 flex-1 min-w-0">
                <input
                  type="checkbox"
                  checked={task.completed}
                  onChange={() => handleToggleComplete(task.id)}
                  className="h-4 w-4 rounded border-gray-300 dark:border-gray-600 text-green-500 focus:ring-green-500 dark:focus:ring-green-400"
                />
                <span
                  className={`flex-1 text-sm ${
                    task.completed 
                      ? "line-through text-gray-400 dark:text-gray-500" 
                      : "text-gray-900 dark:text-gray-100"
                  } truncate`}
                >
                  {task.text}
                </span>
                <span className={`text-xs px-2 py-1 rounded-full ${getPriorityColor(task.priority)} flex-shrink-0`}>
                  {task.priority}
                </span>
              </div>
              <button
                onClick={() => handleDeleteTask(task.id)}
                className="text-gray-400 dark:text-gray-500 hover:text-red-500 dark:hover:text-red-400 transition-colors p-1 ml-2"
                aria-label="Delete task"
              >
                <FaTrash size={14} />
              </button>
            </motion.div>
          ))}
        </AnimatePresence>
        {todos.length === 0 && (
          <div className="text-center py-8">
            <p className="text-gray-500 dark:text-gray-400 text-sm">No tasks yet. Add one above!</p>
          </div>
        )}
      </div>
    </motion.div>
  )
}

export default TodoWidget

import { useState, useEffect } from "react"
import { motion } from "framer-motion"
import { FaSync, FaDownload, FaCheckCircle, FaClock } from "react-icons/fa"
import { collection, query, where, onSnapshot } from "firebase/firestore"
import { db } from "../utils/firebase"
import { useAuth } from "../context/AuthContext"

const WeeklyDataSyncWidget = () => {
  const { currentUser } = useAuth()
  const [weeklyData, setWeeklyData] = useState({
    tasksCompleted: 0,
    tasksPending: 0,
    habitsCompleted: 0,
    habitsTotal: 0,
    goalsProgress: 0,
  })
  const [loading, setLoading] = useState(true)
  const [lastSync, setLastSync] = useState(null)

  useEffect(() => {
    if (!currentUser) return

    const unsubscribes = []

    // Get start of current week -->
    const now = new Date()
    const startOfWeek = new Date(now.setDate(now.getDate() - now.getDay()))
    startOfWeek.setHours(0, 0, 0, 0)

    // Todos -->
    const todosQuery = query(collection(db, "todos"), where("userId", "==", currentUser.uid))
    const unsubscribeTodos = onSnapshot(todosQuery, (snapshot) => {
      let completed = 0
      let pending = 0

      snapshot.forEach((doc) => {
        const data = doc.data()
        const createdAt = new Date(data.createdAt)

        if (createdAt >= startOfWeek) {
          if (data.completed) {
            completed++
          } else {
            pending++
          }
        }
      })

      setWeeklyData((prev) => ({ ...prev, tasksCompleted: completed, tasksPending: pending }))
    })

    // Habits -->
    const habitsQuery = query(collection(db, "habits"), where("userId", "==", currentUser.uid))
    const unsubscribeHabits = onSnapshot(habitsQuery, (snapshot) => {
      let totalHabits = 0
      let completedHabits = 0

      snapshot.forEach((doc) => {
        const data = doc.data()
        if (data.days && Array.isArray(data.days)) {
          totalHabits += data.days.length
          completedHabits += data.days.filter((day) => day).length
        }
      })

      setWeeklyData((prev) => ({
        ...prev,
        habitsCompleted: completedHabits,
        habitsTotal: totalHabits,
      }))
    })

    // Goals -->
    const goalsQuery = query(collection(db, "goals"), where("userId", "==", currentUser.uid))
    const unsubscribeGoals = onSnapshot(goalsQuery, (snapshot) => {
      let totalProgress = 0
      let goalCount = 0

      snapshot.forEach((doc) => {
        const data = doc.data()
        if (data.targetValue && data.currentValue !== undefined) {
          totalProgress += Math.min((data.currentValue / data.targetValue) * 100, 100)
          goalCount++
        }
      })

      const avgProgress = goalCount > 0 ? Math.round(totalProgress / goalCount) : 0
      setWeeklyData((prev) => ({ ...prev, goalsProgress: avgProgress }))
    })

    unsubscribes.push(unsubscribeTodos, unsubscribeHabits, unsubscribeGoals)
    setLoading(false)
    setLastSync(new Date())

    return () => {
      unsubscribes.forEach((unsubscribe) => unsubscribe())
    }
  }, [currentUser])

  const exportWeeklyData = () => {
    const exportData = {
      weekOf: new Date().toISOString().split("T")[0],
      summary: weeklyData,
      exportedAt: new Date().toISOString(),
      userId: currentUser?.uid,
    }

    const dataStr = JSON.stringify(exportData, null, 2)
    const dataBlob = new Blob([dataStr], { type: "application/json" })
    const url = URL.createObjectURL(dataBlob)

    const link = document.createElement("a")
    link.href = url
    link.download = `weekly-summary-${new Date().toISOString().split("T")[0]}.json`
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)

    URL.revokeObjectURL(url)
  }

  const getCompletionRate = () => {
    const totalTasks = weeklyData.tasksCompleted + weeklyData.tasksPending
    if (totalTasks === 0) return 0
    return Math.round((weeklyData.tasksCompleted / totalTasks) * 100)
  }

  const getHabitRate = () => {
    if (weeklyData.habitsTotal === 0) return 0
    return Math.round((weeklyData.habitsCompleted / weeklyData.habitsTotal) * 100)
  }

  return (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="card">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center">
          <FaSync className="h-5 w-5 text-green-500 mr-2" />
          <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Weekly Summary</h2>
        </div>
        <button
          onClick={exportWeeklyData}
          className="p-2 text-green-500 hover:text-green-600 dark:hover:text-green-400 transition-colors"
          title="Export weekly data"
        >
          <FaDownload size={14} />
        </button>
      </div>

      {loading ? (
        <div className="animate-pulse space-y-3">
          {[...Array(3)].map((_, i) => (
            <div key={i} className="h-4 bg-gray-200 dark:bg-gray-700 rounded"></div>
          ))}
        </div>
      ) : (
        <div className="space-y-4">
          {/* Tasks Summary */}
          <div className="flex items-center justify-between p-3 bg-green-50 dark:bg-green-900/20 rounded-lg">
            <div className="flex items-center">
              <FaCheckCircle className="text-green-500 mr-2" size={16} />
              <div>
                <p className="text-sm font-medium text-gray-900 dark:text-white">Tasks</p>
                <p className="text-xs text-gray-600 dark:text-gray-400">
                  {weeklyData.tasksCompleted} completed, {weeklyData.tasksPending} pending
                </p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-lg font-bold text-green-600 dark:text-green-400">{getCompletionRate()}%</p>
            </div>
          </div>

          {/* Habits Summary */}
          <div className="flex items-center justify-between p-3 bg-blue-50 dark:bg-blue-900/20 rounded-lg">
            <div className="flex items-center">
              <FaClock className="text-blue-500 mr-2" size={16} />
              <div>
                <p className="text-sm font-medium text-gray-900 dark:text-white">Habits</p>
                <p className="text-xs text-gray-600 dark:text-gray-400">
                  {weeklyData.habitsCompleted} / {weeklyData.habitsTotal} completed
                </p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-lg font-bold text-blue-600 dark:text-blue-400">{getHabitRate()}%</p>
            </div>
          </div>

          {/* Goals Progress */}
          <div className="flex items-center justify-between p-3 bg-purple-50 dark:bg-purple-900/20 rounded-lg">
